import{_ as t,o as i,c as h,ag as a}from"./chunks/framework.CvgP6Fyv.js";const r=JSON.parse('{"title":"Thực Chiến: Mời 500 KOC/Tuần","description":"Cầm tay chỉ việc cách dùng HappyAgent để tự động hóa mời KOC (Use case thực tế)","frontmatter":{"title":"Thực Chiến: Mời 500 KOC/Tuần","description":"Cầm tay chỉ việc cách dùng HappyAgent để tự động hóa mời KOC (Use case thực tế)","robots":"index, follow"},"headers":[],"relativePath":"sop/step-by-step.md","filePath":"sop/step-by-step.md"}'),c={name:"sop/step-by-step.md"};function o(e,n,s,l,g,p){return i(),h("div",null,[...n[0]||(n[0]=[a(`<h1 id="🎯-thuc-chien-cach-tu-đong-moi-500-koc-moi-tuan" tabindex="-1">🎯 Thực Chiến: Cách Tự Động Mời 500 KOC Mỗi Tuần <a class="header-anchor" href="#🎯-thuc-chien-cach-tu-đong-moi-500-koc-moi-tuan" aria-label="Permalink to &quot;🎯 Thực Chiến: Cách Tự Động Mời 500 KOC Mỗi Tuần&quot;">​</a></h1><blockquote><p>Hệ thống đã cài đặt xong. Bây giờ là lúc dùng nó để ra số. Đây là Use Case tiêu chuẩn cho bộ phận Vận hành/CSKH. Hãy đi theo đúng trình tự này, bạn chỉ mất đúng 5 phút mỗi sáng!</p></blockquote><hr><h2 id="🕒-buoc-1-8h-sang-cap-nhat-luong-moi-file-excel" tabindex="-1">🕒 Bước 1: 8h Sáng - Cập Nhật &quot;Luồng Mồi&quot; (File Excel) <a class="header-anchor" href="#🕒-buoc-1-8h-sang-cap-nhat-luong-moi-file-excel" aria-label="Permalink to &quot;🕒 Bước 1: 8h Sáng - Cập Nhật &quot;Luồng Mồi&quot; (File Excel)&quot;">​</a></h2><p>Hàng tuần/Hàng ngày, khi bạn đã lọc được danh sách KOC cần liên hệ bằng tay, hãy làm như sau:</p><ol><li>Copy toàn bộ thông tin đó.</li><li>Tìm thư mục <code>config</code> trên máy tính (nơi bộ kỹ thuật đã thiết lập cho bạn).</li><li>Mở file có tên <code>creators.csv</code> lên (Có thể bấm chuột phải chọn <strong>Open with Excel</strong> hoặc <strong>Notepad</strong>).</li><li>Dán thông tin vào theo đúng cột. Ví dụ có cột <code>id_tiktok</code>, <code>link_profile</code>, vân vân.</li><li>Bấm <code>Ctrl+S</code> (Windows) hoặc <code>Cmd+S</code> (Mac) để lưu lại tệp này. Đóng nó đi.</li></ol><p><em>Xong. HappyAgent bây giờ đã biết hôm nay bạn muốn mời ai.</em></p><hr><h2 id="✍️-buoc-2-8h05-sang-viet-kich-ban-phu-hop" tabindex="-1">✍️ Bước 2: 8h05 Sáng - Viết Kịch Bản Phù Hợp <a class="header-anchor" href="#✍️-buoc-2-8h05-sang-viet-kich-ban-phu-hop" aria-label="Permalink to &quot;✍️ Bước 2: 8h05 Sáng - Viết Kịch Bản Phù Hợp&quot;">​</a></h2><p>Bạn đang chạy Campaign Sale Tết và muốn mời họ tham gia? Hãy vào chỉnh lại tin nhắn cho đúng ngữ cảnh!</p><ol><li>Tại chính thư mục <code>config</code>, có một file tên là <code>message-template.json</code>.</li><li>Bấm chuột phải, chọn <strong>Mở bằng Notepad</strong> (trên máy Win) hoặc TextEdit (trên máy Mac). Bạn sẽ thấy nội dung tương tự thế này:<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   &quot;loi_chao&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Chào bạn, mình từ Team Boxme!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   &quot;noi_dung&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Sắp tới có Sale lớn, team mình rất muốn booking bạn làm video.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   &quot;chi_tiet_link&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://campaigntet.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>Bạn dùng chuột, <strong>sửa nội dung màu xanh lá (hoặc cam) nằm giữa các cặp ngoặc kép <code>&quot;&quot;</code></strong>. Chú ý ĐỪNG xoá mất thẻ ngoặc kép của hệ thống.</li><li>Lưu tệp lại (<code>Ctrl+S</code>).</li></ol><p><em>Lưu ý: Nếu bạn có nhiều dạng chiến dịch (Mời KOC Beauty, Mời KOC Thời trang), tốt nhất là chuẩn bị sẵn nội dung trong file Word rồi copy thả vào đây mỗi sáng.</em></p><hr><h2 id="🚀-buoc-3-8h10-sang-bam-nut-chay-uong-ca-phe" tabindex="-1">🚀 Bước 3: 8h10 Sáng - Bấm Nút Chạy &amp; Uống Cà Phê <a class="header-anchor" href="#🚀-buoc-3-8h10-sang-bam-nut-chay-uong-ca-phe" aria-label="Permalink to &quot;🚀 Bước 3: 8h10 Sáng - Bấm Nút Chạy &amp; Uống Cà Phê&quot;">​</a></h2><p>Bạn đã nói cho AI biết &quot;<em>Cần mời ai</em>&quot; và &quot;<em>Nói cái gì</em>&quot;. Việc cuối cùng là khởi chạy công tắc.</p><ol><li>Bấm đúp vào biểu tượng (Shortcut/Lệnh) do đội Dev cài săn ngoài màn hình máy tính của bạn. (Hoặc nếu mở Terminal, đánh dòng chữ ngắn gọn: <code>npm start</code> rồi bấm <code>Enter</code>).</li><li>Một màn hình xuất hiện các chữ chạy liên tục như &quot;Đang tải cấu hình...&quot;, &quot;Đang khởi động Shop 1...&quot;. <strong>Kệ nó</strong>.</li><li>Bạn cứ việc thu nhỏ cửa sổ. Thu nhỏ lại và lướt Web hoặc check tin nhắn khác.</li></ol><p>Hệ thống sẽ chạy ngầm bằng công nghệ ẩn danh CloakBrowser, hoàn toàn không chiếm màn hình của bạn. Lâu lâu, nếu ứng dụng chớp màn hình Terminal màu xanh đỏ tức là nó thông báo 1 nick đã chạy xong!</p><hr><h2 id="📊-buoc-4-kiem-tra-thanh-qua" tabindex="-1">📊 Bước 4: Kiểm Tra Thành Quả <a class="header-anchor" href="#📊-buoc-4-kiem-tra-thanh-qua" aria-label="Permalink to &quot;📊 Bước 4: Kiểm Tra Thành Quả&quot;">​</a></h2><p>Ai cũng muốn nhìn thấy &quot;tiền rơi vào túi&quot;.</p><p>Sau tầm nửa tiếng hãy mở <strong>Bảng điều khiển (Dashboard)</strong>:</p><ul><li>Đội Dev đã cài sẵn nó dưới dạng liên kết web cục bộ (<code>http://localhost...</code> hoặc một trang web chỉ máy bạn xem được).</li><li>Truy cập nó, đập vào mắt bạn là: Biểu đồ <strong>Thành Công</strong> (Màu Xanh), <strong>Thất Bại</strong> (Màu Đỏ do KOC đó khóa tin nhắn người lạ hoặc lỗi).</li><li>Hãy lấy danh sách &quot;Thành Công&quot; gửi cho cấp trên của bạn báo cáo hiệu suất sáng hôm nay.</li></ul><p>✨ <strong>Chúc mừng bạn! Việc trước đây cần 4 tiếng click tay nay đã gộp vào 10 phút đầu giờ sáng. Bạn là bậc thầy vận hành tiếp theo với AI!</strong></p>`,23)])])}const d=t(c,[["render",o]]);export{r as __pageData,d as default};
